+    // --- 1. Frame roundtrips ---
+
+    #[test]
+    fn frame_roundtrip_data() {
+        let frame = H3Frame::Data(vec![0xCA, 0xFE]);
+        let mut buf = Vec::new();
+        frame.encode(&mut buf).expect("encode");
+        let (decoded, consumed) = H3Frame::decode(&buf).expect("decode");
+        assert_eq!(decoded, frame);
+        assert_eq!(consumed, buf.len());
+    }
