+        // 201 is not in the QPACK static table, so the first entry must be Literal.
+        assert_eq!(
+            plan[0],
+            QpackFieldPlan::Literal {
+                name: ":status".to_string(),
+                value: "201".to_string(),
+            }
+        );
+    }
